INSERT INTO public.project_operation_alerts (project_id, nome, severidade, significado, acao, sort_order) VALUES ('app-banking', 'HIGH_LATENCY_PIX', 'Alta', 'Tempo de resposta do Pix acima de 3s. Pode indicar gargalo no serviço de pagamentos ou timeout com o Bacen.', 'Verificar logs do serviço pix-processor e métricas de fila Kafka.', 0);
INSERT INTO public.project_operation_alerts (project_id, nome, severidade, significado, acao, sort_order) VALUES ('app-banking', 'DB_CONNECTION_POOL_EXHAUSTED', 'Alta', 'Pool de conexões com o PostgreSQL esgotado. Risco de indisponibilidade do app.', 'Aumentar pool temporariamente e investigar queries lentas com EXPLAIN ANALYZE.', 1);
INSERT INTO public.project_operation_alerts (project_id, nome, severidade, significado, acao, sort_order) VALUES ('app-banking', 'FAILED_LOGIN_SPIKE', 'Média', 'Pico de tentativas de login com falha. Possível ataque de credential stuffing.', 'Ativar rate limiting e notificar time de segurança via #seguranca-banking.', 2);
INSERT INTO public.project_operation_alerts (project_id, nome, severidade, significado, acao, sort_order) VALUES ('app-banking', 'CERT_EXPIRY_WARNING', 'Baixa', 'Certificado SSL/TLS com menos de 30 dias para expirar.', 'Renovar certificado via painel da AWS Certificate Manager.', 3);
INSERT INTO public.project_operation_diagnostics (project_id, step_text, sort_order) VALUES ('app-banking', '1. Verificar o status de saúde no painel de observabilidade (Datadog)', 0);
INSERT INTO public.project_operation_diagnostics (project_id, step_text, sort_order) VALUES ('app-banking', '2. Checar os logs do serviço afetado filtrando por nível ERROR nos últimos 30 min', 1);
INSERT INTO public.project_operation_diagnostics (project_id, step_text, sort_order) VALUES ('app-banking', '3. Verificar se há deploy recente que possa ter introduzido a regressão', 2);
INSERT INTO public.project_operation_diagnostics (project_id, step_text, sort_order) VALUES ('app-banking', '4. Analisar métricas de CPU, memória e latência nos dashboards de infra', 3);
INSERT INTO public.project_operation_diagnostics (project_id, step_text, sort_order) VALUES ('app-banking', '5. Confirmar se o problema é isolado a um microsserviço ou afeta toda a plataforma', 4);
INSERT INTO public.project_operation_diagnostics (project_id, step_text, sort_order) VALUES ('app-banking', '6. Acionar o responsável técnico do squad afetado via canal #incidentes-banking', 5);
INSERT INTO public.project_operation_diagnostics (project_id, step_text, sort_order) VALUES ('app-banking', '7. Abrir post-mortem no Confluence após resolução para documentar aprendizados', 6);
